# Implement the Inventory class with the specified attributes and methods
class Inventory:
    def __init__(self):
        self.products = {}

    def add_product(self, product_name, quantity):
        if product_name in self.products:
            self.products[product_name] += quantity
        else:
            self.products[product_name] = quantity

    def check_stock(self, product_name):
        return self.products.get(product_name, "Product not found")

# Do not modify the code below. This function will be called during testing.
def default_test():
    inventory = Inventory()
    inventory.add_product("Laptops", 10)
    inventory.add_product("Smartphones", 50)
    print(inventory.check_stock("Laptops"))  # Expected output: 8
    print(inventory.check_stock("Smartphones"))  # Expected output: 50
